import{c as t,cN as e,cG as d,cb as a,c8 as n,cf as r,cT as l,ce as s,cg as o}from"./chunks/framework.BlkIsu1j.js";const i=JSON.parse('{"title":"Claude Code 学习教程","description":"","frontmatter":{"title":"Claude Code 学习教程","outline":"deep","layout":"doc","prev":false,"next":"/ai/claudecodenew/01-ai-coding-era","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/index.md","filePath":"ai/claudecodenew/index.md","lastUpdated":1780826493000}'),h={id:"frontmatter-title",tabindex:"-1"};const p=t({name:"ai/claudecodenew/index.md"},[["render",function(t,i,p,g,c,u){const C=e("vitepress-mermaid");return d(),a("div",null,[n("h1",h,[r(l(t.$frontmatter.title)+" ",1),i[0]||(i[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),i[1]||(i[1]=s('<h2 id="关于本书" tabindex="-1">关于本书 <a class="header-anchor" href="#关于本书" aria-label="Permalink to “关于本书”">​</a></h2><p>这是一本<strong>系统性的 Claude Code 学习教程</strong>，以 Claude Code for VSCode 扩展为主要工具，以 DeepSeek V4 系列模型（通过 cc-switch 接入）为默认模型，带你从零基础逐步成长为 Claude Code 高手。</p><p>本书不同于市面上零散的博客文章或快速入门指南。它是一本<strong>结构完整、由浅入深、理论与实践并重</strong>的教程——全书共 8 篇、40 章、7 个附录，覆盖从安装配置到团队推广、从基础对话到自定义扩展开发的完整知识体系。</p><p><strong>本书特色：</strong></p><ul><li><strong>工具聚焦</strong>：以 Claude Code for VSCode 为主线，所有操作、截图、案例均基于 VSCode 扩展，确保读者可复现</li><li><strong>模型实战</strong>：默认使用 DeepSeek V4 系列模型（V4 Flash / V4 Pro），大幅降低使用成本，同时支持 Anthropic 官方模型作为补充</li><li><strong>混合定位</strong>：兼顾零基础开发者和有 AI 工具经验的读者，每篇提供明确的学习入口建议</li><li><strong>体系完整</strong>：8 篇 40 章 + 7 个附录，从入门到精通，从概念到实战，从个人使用到团队推广</li></ul><p>无论你是第一次接触 AI 编程工具，还是已经使用过 Copilot、Cursor 等工具想深入了解 Agentic Coding，本书都能为你提供清晰的学习路径。</p><hr><h2 id="核心概念-agent-与模型" tabindex="-1">核心概念：Agent 与模型 <a class="header-anchor" href="#核心概念-agent-与模型" aria-label="Permalink to “核心概念：Agent 与模型”">​</a></h2><p>初次接触 Claude Code 时，最容易混淆的是 <strong>Agent</strong> 和 <strong>模型</strong> 的关系。理清这两个概念，是正确理解 Claude Code 工作方式的第一步。</p><h3 id="claude-code-是什么" tabindex="-1">Claude Code 是什么？ <a class="header-anchor" href="#claude-code-是什么" aria-label="Permalink to “Claude Code 是什么？”">​</a></h3><p><strong>Claude Code 是一个 Agent</strong>——它是一个软件框架/工具，负责：</p><ul><li>管理你和 AI 模型之间的对话</li><li>调用工具（读文件、写代码、执行命令、搜索网络等）</li><li>控制权限（决定何时需要你的确认）</li><li>维护上下文（CLAUDE.md、Memory、对话历史）</li><li>协调多个模型的调度</li></ul>',12)),o(C,{value:'flowchart TB\n    subgraph SHELLS["🖥️ Shell / Client Layer（使用界面）"]\n        direction TB\n        E1["📟 CLI<br>（终端命令行）"]\n        E2["🌐 Web UI<br>（claude.ai/code）"]\n        E3["💻 VSCode 扩展<br>（推荐）"]\n        E4["🧩 JetBrains 插件<br>（IntelliJ/PyCharm）"]\n        E5["🖲️ Desktop App<br>（独立应用）"]\n    end\n\n    SHELLS --\x3e AGENT\n\n    subgraph AGENT["Claude Code（Agent）"]\n        direction LR\n\n        subgraph CORE["🧠 Core Runtime"]\n            direction TB\n            A1["对话 / 规划"]\n            A2["工具编排"]\n            A3["权限与安全控制"]\n            A4["上下文管理<br>（CLAUDE.md / Memory）"]\n            A5["会话管理<br>（Save / Resume）"]\n        end\n\n        subgraph TOOLS["🔧 工具系统"]\n            direction TB\n            B1["文件系统"]\n            B2["终端 / Shell"]\n            B3["Git 集成"]\n            B4["Web 搜索 / 获取"]\n            B5["MCP 服务器"]\n            B6["网络请求"]\n            B7["图像 / PDF 读取"]\n        end\n\n        subgraph EXT["🧩 扩展生态"]\n            direction TB\n            C1["Skills<br>（技能 / 工作流）"]\n            C2["Plugins<br>（MCP 插件）"]\n            C3["Hooks<br>（事件钩子）"]\n            C4["斜杠命令<br>（/help 等）"]\n            C5["键盘快捷键<br>（Keymap）"]\n        end\n    end\n\n    AGENT --\x3e API["调用模型 API"]\n\n    subgraph MODELS["🤖 模型层"]\n        direction TB\n        subgraph OFFICIAL["Anthropic 官方模型"]\n            D1["Claude Opus 4.7"]\n            D2["Claude Sonnet 4.6"]\n            D3["Claude Haiku 4.5"]\n        end\n        D4["第三方模型<br>（DeepSeek / OpenAI 等）"]\n    end\n\n    API --\x3e OFFICIAL\n    API -. 通过 cc-switch 接入 .-> D4'}),i[2]||(i[2]=s('<h3 id="claude-模型家族" tabindex="-1">Claude 模型家族 <a class="header-anchor" href="#claude-模型家族" aria-label="Permalink to “Claude 模型家族”">​</a></h3><p><strong>模型是 Agent 的&quot;大脑&quot;</strong>——它提供理解和生成代码的智能。Anthropic 提供三个等级的模型：</p><table tabindex="0"><thead><tr><th>模型</th><th>定位</th><th>特点</th><th>适用场景</th><th style="text-align:center;">总结</th></tr></thead><tbody><tr><td><strong>Claude Opus 4.7</strong></td><td>旗舰级</td><td>最强推理、最深理解、最准代码</td><td>复杂架构设计、深度调试、跨文件大规模重构</td><td style="text-align:center;">强</td></tr><tr><td><strong>Claude Sonnet 4.6</strong></td><td>主力级</td><td>性能与速度的最佳平衡</td><td>日常编程、Bug 修复、功能开发（推荐默认使用）</td><td style="text-align:center;">平衡模式</td></tr><tr><td><strong>Claude Haiku 4.5</strong></td><td>轻量级</td><td>最快响应、最低成本</td><td>简单查询、代码格式化、文档整理</td><td style="text-align:center;">快</td></tr></tbody></table><p>三者使用完全相同的 Agent 框架和工具系统，区别仅在于推理能力和速度。</p><h3 id="agent-与模型的关系" tabindex="-1">Agent 与模型的关系 <a class="header-anchor" href="#agent-与模型的关系" aria-label="Permalink to “Agent 与模型的关系”">​</a></h3><h4 id="一个简单的类比" tabindex="-1">一个简单的类比 <a class="header-anchor" href="#一个简单的类比" aria-label="Permalink to “一个简单的类比”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Agent = 汽车（方向盘、油门、刹车、导航）</span></span>\n<span class="line"><span>模型  = 发动机（提供动力）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>换模型 ≈ 换发动机（同样的车，不同的马力）</span></span>\n<span class="line"><span>Agent 的能力 × 模型的智能 = 最终产出</span></span></code></pre></div><p>具体来说：</p><ul><li><strong>Agent 决定&quot;能做什么&quot;</strong>：能读什么文件、能执行哪些命令、能否搜索网络、何时需要你确认——这些都是 Agent 层面的事，与使用哪个模型无关。</li><li><strong>模型决定&quot;做得有多好&quot;</strong>：代码质量、逻辑推理深度、对复杂需求的理解——这些取决于模型能力。Opus 写的代码可能比 Haiku 更优雅，但它们用的都是同一套工具。</li><li><strong>你可以随时切换模型</strong>：通过 cc-switch 在不同模型间切换（甚至接入 DeepSeek 等第三方模型），Agent 的行为框架保持不变，但输出质量会随模型而变化。</li></ul><h4 id="为什么这个区别很重要" tabindex="-1">为什么这个区别很重要？ <a class="header-anchor" href="#为什么这个区别很重要" aria-label="Permalink to “为什么这个区别很重要？”">​</a></h4><p>理解 Agent 和模型的分离，能帮你做出更好的决策：</p><ul><li><strong>Agent 行为出问题</strong>（如改错文件、没读上下文）→ 检查 CLAUDE.md、对话状态、权限配置，换模型没用</li><li><strong>输出质量出问题</strong>（如代码不够好、逻辑不严谨）→ 切换到更强的模型（Sonnet → Opus）</li><li><strong>想省钱但 Agent 能力不受影响</strong> → 日常用 Haiku/Sonnet，复杂任务切 Opus</li></ul><h3 id="deepseek-模型家族" tabindex="-1">DeepSeek 模型家族 <a class="header-anchor" href="#deepseek-模型家族" aria-label="Permalink to “DeepSeek 模型家族”">​</a></h3><p>除了 Anthropic 官方模型，本书默认使用 <strong>DeepSeek V4 系列模型</strong>，通过 cc-switch 工具接入 Claude Code。DeepSeek V4 是目前性价比极高的第三方模型选择：</p><table tabindex="0"><thead><tr><th>模型</th><th>定位</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>DeepSeek V4 Pro</strong></td><td>旗舰级</td><td>最强推理能力，接近 Claude Opus 水平</td><td>复杂任务、深度分析、架构设计</td></tr><tr><td><strong>DeepSeek V4 Flash</strong></td><td>主力级</td><td>快速响应，成本极低</td><td>日常开发、代码生成、文档整理</td></tr></tbody></table><h3 id="模型定价对比" tabindex="-1">模型定价对比 <a class="header-anchor" href="#模型定价对比" aria-label="Permalink to “模型定价对比”">​</a></h3><p>选择合适的模型，成本是一个重要考量因素。以下是各模型的参考价格：</p><table tabindex="0"><thead><tr><th>模型</th><th>输入价格（每百万 Token）</th><th>输出价格（每百万 Token）</th><th style="text-align:center;">性价比评级</th></tr></thead><tbody><tr><td>Claude Opus 4.7</td><td>$15.00</td><td>$75.00</td><td style="text-align:center;">★★☆☆☆</td></tr><tr><td>Claude Sonnet 4.6</td><td>$3.00</td><td>$15.00</td><td style="text-align:center;">★★★☆☆</td></tr><tr><td>Claude Haiku 4.5</td><td>$0.80</td><td>$4.00</td><td style="text-align:center;">★★★★☆</td></tr><tr><td>DeepSeek V4 Pro</td><td>$1.50</td><td>$6.00</td><td style="text-align:center;">★★★★★</td></tr><tr><td>DeepSeek V4 Flash</td><td>$0.30</td><td>$1.20</td><td style="text-align:center;">★★★★★</td></tr></tbody></table><blockquote><p>注：价格为 2026 年 5 月参考值，实际价格请以各平台官网为准。DeepSeek 模型的价格优势非常显著——在大多数日常场景中，使用 DeepSeek V4 Flash 的成本仅为 Claude Sonnet 的 1/10 甚至更低。</p></blockquote><h3 id="模型选择建议" tabindex="-1">模型选择建议 <a class="header-anchor" href="#模型选择建议" aria-label="Permalink to “模型选择建议”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>推荐模型</th><th>理由</th></tr></thead><tbody><tr><td>日常开发、代码生成</td><td>DeepSeek V4 Flash</td><td>成本极低，日常任务表现足够好</td></tr><tr><td>复杂重构、架构设计</td><td>DeepSeek V4 Pro</td><td>推理能力强，接近 Opus 但成本低得多</td></tr><tr><td>深度调试、疑难杂症</td><td>Claude Opus 4.7</td><td>最强推理，值得为关键任务投入</td></tr><tr><td>简单查询、文档整理</td><td>DeepSeek V4 Flash</td><td>成本最低，响应最快</td></tr><tr><td>代码审查、安全检查</td><td>Claude Sonnet 4.6</td><td>平衡模式，审查质量有保障</td></tr></tbody></table><p><strong>本书的建议策略</strong>：日常开发默认使用 DeepSeek V4 Flash，遇到复杂任务切换到 DeepSeek V4 Pro，关键决策和深度分析时按需使用 Claude Opus。通过 cc-switch 可以在这些模型之间无缝切换——第 3 章会详细讲解配置方法。</p><hr><h2 id="本书特色" tabindex="-1">本书特色 <a class="header-anchor" href="#本书特色" aria-label="Permalink to “本书特色”">​</a></h2><h3 id="工具聚焦" tabindex="-1">工具聚焦 <a class="header-anchor" href="#工具聚焦" aria-label="Permalink to “工具聚焦”">​</a></h3><p>全书以 <strong>Claude Code for VSCode</strong> 为主要工具。所有操作步骤、界面截图、快捷键示例均基于 VSCode 扩展，确保读者可以一边阅读一边在自己的编辑器中实践。同时也会介绍 CLI、JetBrains 插件等其他平台的使用方式，方便不同环境的读者。</p><h3 id="模型实战" tabindex="-1">模型实战 <a class="header-anchor" href="#模型实战" aria-label="Permalink to “模型实战”">​</a></h3><p>不同于大多数教程默认使用 Claude Sonnet，本书<strong>以 DeepSeek V4 系列为默认模型</strong>。这不仅大幅降低了学习成本（DeepSeek V4 Flash 的价格约为 Claude Sonnet 的 1/10），也展示了 Claude Code 作为 Agent 的模型无关性——你可以自由选择性价比最高的模型，而不被锁定在特定供应商。</p><h3 id="混合定位" tabindex="-1">混合定位 <a class="header-anchor" href="#混合定位" aria-label="Permalink to “混合定位”">​</a></h3><p>本书同时服务两类读者：</p><ul><li><strong>零基础开发者</strong>：从第一篇开始，逐步建立对 AI Agent 编程工具的完整认知</li><li><strong>有 AI 工具经验的开发者</strong>：可以从第二篇或第三篇切入，快速定位到你需要的内容</li></ul><p>每篇开头都标注了建议的阅读起点，你可以根据自己的背景灵活选择学习路径。</p><h3 id="体系完整" tabindex="-1">体系完整 <a class="header-anchor" href="#体系完整" aria-label="Permalink to “体系完整”">​</a></h3><p>本书不是碎片化的技巧合集，而是一本<strong>结构严谨的教程</strong>：</p><ul><li><strong>8 篇 40 章</strong>：从概念认知到高级工作流，覆盖 Claude Code 的全部能力</li><li><strong>贯穿项目</strong>：第八篇的 SmartTodo 全栈应用贯穿全书，理论知识与动手实践交替进行</li><li><strong>7 个附录</strong>：提供 Cheatsheet、配置参考、Prompt 模板等速查资料，方便日常查阅</li></ul><hr><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to “学习路径”">​</a></h2><p>全书共 8 篇 40 章，按学习深度线性推进，每一篇都是下一篇的前置基础：</p><table tabindex="0"><thead><tr><th style="text-align:center;">篇</th><th>名称</th><th>章节</th><th>目标</th></tr></thead><tbody><tr><td style="text-align:center;">一</td><td>入门篇</td><td>Ch 1-4</td><td>建立认知，完成环境搭建</td></tr><tr><td style="text-align:center;">二</td><td>基础篇</td><td>Ch 5-9</td><td>掌握四大核心能力</td></tr><tr><td style="text-align:center;">三</td><td>进阶篇</td><td>Ch 10-14</td><td>理解内部机制，掌握配置与权限</td></tr><tr><td style="text-align:center;">四</td><td>生态篇</td><td>Ch 15-19</td><td>掌握 MCP、Plugins、Skills、Hooks 扩展生态</td></tr><tr><td style="text-align:center;">五</td><td>实战篇</td><td>Ch 20-27</td><td>通过 8 个真实场景融会贯通</td></tr><tr><td style="text-align:center;">六</td><td>方法论篇</td><td>Ch 28-31</td><td>建立 AI 编程思维</td></tr><tr><td style="text-align:center;">七</td><td>精通篇</td><td>Ch 32-36</td><td>高级工作流、团队推广、前沿探索</td></tr><tr><td style="text-align:center;">八</td><td>贯穿项目</td><td>Ch 37-40</td><td>从零构建全栈应用</td></tr></tbody></table><p><strong>各篇概览：</strong></p><ul><li><p><strong>第一篇 入门篇</strong>：回答&quot;Claude Code 是什么、能做什么、怎么装&quot;。包含 AI 编程时代背景、Agent 与模型核心概念、环境搭建、平台生态概览。完成本篇后，你将跑通第一个对话，理解 Claude Code 的基本工作方式。</p></li><li><p><strong>第二篇 基础篇</strong>：掌握日常开发的四大核心能力——对话与代码理解、代码编辑与重构、终端命令执行、Git 集成。同时学习权限模式切换和模型 Effort 设置。完成本篇后，你将能在日常工作中流畅使用 Claude Code。</p></li><li><p><strong>第三篇 进阶篇</strong>：深入 Agent Loop 内部机制，全面理解工具系统，掌握上下文管理、CLAUDE.md 编写、四层配置体系、权限与安全配置。完成本篇后，你将能够为项目定制 Claude Code 的行为。</p></li><li><p><strong>第四篇 生态篇</strong>：打开 Claude Code 的扩展能力边界——MCP 协议与服务器、插件系统、Skills 技能系统、Hooks 钩子系统、命令系统进阶。完成本篇后，你将能够利用社区生态大幅扩展 Claude Code 的能力。</p></li><li><p><strong>第五篇 实战篇</strong>：通过 8 个真实开发场景（理解陌生项目、从零搭建新功能、大规模重构、调试排错、Code Review、测试编写、文档生成、CI/CD 集成），将前四篇的知识融会贯通。每个场景都包含完整的步骤拆解和技巧复盘。</p></li><li><p><strong>第六篇 方法论篇</strong>：超越工具本身，建立 AI 时代的编程思维——Prompt 工程、让 AI 理解你的项目、人机协作模式、效率优化策略。完成本篇后，你将理解&quot;用好 AI&quot;背后的方法论。</p></li><li><p><strong>第七篇 精通篇</strong>：掌握高级工作流（多 Agent 协作、Plan 模式、Worktree 隔离）、自定义扩展开发、团队推广策略、模型深度实测对比、前沿趋势探索。完成本篇后，你将具备在团队中推广 Claude Code 的能力。</p></li><li><p><strong>第八篇 贯穿项目</strong>：从零构建一个完整的全栈应用 SmartTodo，将全书知识落地为一个可部署上线的项目。涵盖项目启动、后端开发、前端开发、部署与运维。</p></li></ul><hr><h2 id="面向读者" tabindex="-1">面向读者 <a class="header-anchor" href="#面向读者" aria-label="Permalink to “面向读者”">​</a></h2><p>本书为不同背景的读者设计了不同的阅读路径：</p><p><strong>零基础开发者</strong>：从第一篇开始，按顺序阅读。第一篇帮你建立完整的认知框架，第二篇让你掌握日常操作，之后逐步深入。建议每读完一篇，在实际项目中练习 1-2 周再继续。</p><p><strong>有 AI 工具经验的开发者</strong>（使用过 Copilot、Cursor 等）：可以从第二篇开始，直接进入 Claude Code 的核心操作。如果对 Agent 和模型的概念已经很清晰，也可以快速浏览第一篇的第 2 章后直接跳到第三篇学习进阶配置。</p><p><strong>团队 Leader / 技术负责人</strong>：重点阅读第七篇（精通篇）中的团队推广章节（第 34 章）和第三篇（进阶篇）中的配置与权限章节（第 13-14 章），了解如何在团队中标准化 Claude Code 的使用。之后可以根据需要深入其他篇章。</p><p><strong>推荐阅读节奏</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>零基础：    第一篇 → 第二篇 → 实战练习 → 第三篇 → 第四篇 → 第五篇 → 第六篇 → 第七篇 → 第八篇</span></span>\n<span class="line"><span>有经验：    快速浏览第一篇 → 第二篇 → 第三篇 → 选择感兴趣的篇章深入</span></span>\n<span class="line"><span>Team Lead： 第七篇(Ch 34) → 第三篇(Ch 13-14) → 根据团队需要选择其他篇章</span></span></code></pre></div><hr><h2 id="与旧版指南的关系" tabindex="-1">与旧版指南的关系 <a class="header-anchor" href="#与旧版指南的关系" aria-label="Permalink to “与旧版指南的关系”">​</a></h2><p>本仓库中同时存在两个 Claude Code 相关的内容目录：</p><table tabindex="0"><thead><tr><th>内容</th><th>路径</th><th>定位</th><th>体量</th></tr></thead><tbody><tr><td><strong>Claude Code 培训指南</strong>（旧版）</td><td><code>src/ai/claudecode/</code></td><td>快速入门指南，适合快速上手</td><td>7 章</td></tr><tr><td><strong>Claude Code 学习教程</strong>（新版）</td><td><code>src/ai/claudecodenew/</code></td><td>系统性教程，适合深度学习</td><td>8 篇 40 章 + 7 附录</td></tr></tbody></table><p>旧版指南（<code>src/ai/claudecode/</code>）定位为<strong>快速入门</strong>，用最精简的篇幅覆盖安装、基本概念、核心功能、生态和工作流，适合想快速上手的朋友。新版教程（<code>src/ai/claudecodenew/</code>）则是<strong>完整的学习体系</strong>，适合希望系统掌握 Claude Code、从&quot;会用&quot;到&quot;精通&quot;的读者。</p><p>两者的关系可以理解为：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>旧版指南 = 快速上手手册（1 小时读完，马上能用）</span></span>\n<span class="line"><span>新版教程 = 完整教材（系统学习，从入门到精通）</span></span></code></pre></div><p>两个版本<strong>长期共存</strong>，互不替代。你可以根据当前需求选择阅读：赶时间就看旧版，想深入就跟着新版走。</p><hr><h2 id="约定与工具" tabindex="-1">约定与工具 <a class="header-anchor" href="#约定与工具" aria-label="Permalink to “约定与工具”">​</a></h2><p>本书全文采用以下约定：</p><table tabindex="0"><thead><tr><th>约定</th><th>说明</th></tr></thead><tbody><tr><td><strong>主要工具</strong></td><td>Claude Code for VSCode（VSCode 扩展）</td></tr><tr><td><strong>默认模型</strong></td><td>DeepSeek V4 Flash / V4 Pro（通过 cc-switch 切换）</td></tr><tr><td><strong>操作系统</strong></td><td>macOS（Windows/Linux 用户大部分操作通用，差异处会特别标注）</td></tr><tr><td><strong>快捷键</strong></td><td>以 Mac 键盘为主，同时标注 Windows/Linux 对应键位</td></tr><tr><td><strong>代码示例</strong></td><td>以 TypeScript / Python 为主，不限定特定语言</td></tr></tbody></table><p>好了，让我们开始这段学习之旅。翻开第一篇，了解 AI 编程时代的到来。</p>',62))])}]]);export{i as __pageData,p as default};
